import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Встановлення Fabric","description":"Покрокова інструкція з встановлення Fabric.","frontmatter":{"title":"Встановлення Fabric","description":"Покрокова інструкція з встановлення Fabric.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"uk_ua/1.20.4/players/installing-fabric.md","filePath":"versions/1.20.4/translated/uk_ua/players/installing-fabric.md","lastUpdated":1739538073000}`);var c={name:`uk_ua/1.20.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Встановлення Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Встановлення Fabric”">​</a></h1><p>Ця інструкція допоможе вам встановити Fabric для офіційного лаунчера Minecraft.</p><p>Для неофіційних лаунчерів слід ознайомитися з їх документацією.</p><h2 id="_1-завантаження-інсталятора-fabric" tabindex="-1">1. Завантаження інсталятора Fabric <a class="header-anchor" href="#_1-завантаження-інсталятора-fabric" aria-label="Permalink to “1. Завантаження інсталятора Fabric”">​</a></h2><p>Ви можете завантажити Інсталятор Fabric з <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">вебсайту Fabric</a>.</p><p>Якщо ви користуєтеся Windows, завантажте версію <code>.exe</code> (<code>Download For Windows</code>), оскільки для цього не потрібно інсталювати Java у вашій системі. Натомість він використовує Java, яка постачається з офіційним лаунчером.</p><p>Для macOS та Linux вам слід завантажити <code>jar</code> версію. Іноді перед цим кроком потрібно встановити Java.</p><h2 id="_2-запуск-інсталятора-fabric" tabindex="-1">2. Запуск інсталятора Fabric <a class="header-anchor" href="#_2-запуск-інсталятора-fabric" aria-label="Permalink to “2. Запуск інсталятора Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Спочатку закрийте Minecraft та його лаунчер перед встановленням.</p></div><details class="details custom-block"><summary>Інформація для користувачів MacOS</summary><p>У macOS вам може знадобитися клацнути правою кнопкою миші файл <code>.jar</code> у каталозі завантажень і натиснути <code>Відкрити</code>, щоб запустити його.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Інсталятор Fabric із виділеним пунктом «Встановити»" loading="lazy"></p><p>Коли вас запитають «Ви впевнені, що хочете відкрити?», знову натисніть <code>Відкрити</code>.</p></details><p>Відкривши інсталятор, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Інсталятор Fabric із виділеним пунктом «Встановити»" loading="lazy"></p><p>Щоб установити Fabric, просто виберіть свою версію гри зі спадного меню та натисніть <code>Встановити</code>.</p><p><strong>Переконайтеся, що встановлено прапорець «Створити профіль».</strong></p><h2 id="_3-готово" tabindex="-1">3. Готово! <a class="header-anchor" href="#_3-готово" aria-label="Permalink to “3. Готово!”">​</a></h2><p>Після завершення встановлення ви можете відкрити лаунчер Minecraft і вибрати профіль Fabric зі спадного списку в нижньому лівому куті та натиснути «Грати»!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Лаунчер Minecraft з вибраним профілем Fabric" loading="lazy"></p><h2 id="наступні-кроки" tabindex="-1">Наступні кроки <a class="header-anchor" href="#наступні-кроки" aria-label="Permalink to “Наступні кроки”">​</a></h2><p>Тепер коли ви встановили Fabric, ви можете додавати моди до своєї гри! Щоб дізнатися більше, перегляньте інструкцію <a href="./finding-mods">Пошук надійних модів</a>.</p><p>Якщо під час виконання цієї інструкції у вас виникнуть проблеми, ви можете звернутися за допомогою в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Діскорд сервері Fabric</a> в каналі <code>#player-support</code>.</p>`,20)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};